  "plan": "Configure nginx to serve on port 80, proxying

 to websockify on 6080 for both HTTP and WebSocket traffic. Then verify everything works and wait for the VM to boot to the Windows 3.11 desktop.",
  "commands": [
    {
      "keystrokes": "sleep 1 && cat /tmp/websockify.log
",
      "duration": 1.0
    },
    {
      "keystrokes": "cat > /etc/nginx/sites-available/novnc << 'EOF'
server {
    listen 80 default_server;
    server_name _;

    location / {
        proxy_pass http://127.0.0.1:6080;
        proxy_http_version 1.1;
        proxy_set_header Upgrade $http_upgrade;
        proxy_set_header Connection "

upgrade\";\n        proxy_set_header Host $host;\n        proxy_set_header X-Real-IP $remote_addr;\n        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;\n        proxy_read_timeout 86400;\n    }\n}\nEOF\n",
      "duration": 0.5
    },
    {
      "keystrokes": "rm -f /etc/nginx/sites-enabled/default\nln -sf /etc/nginx/sites-available/novnc /etc/nginx/sites-enabled/novnc\nnginx -t\n",
